from flask import Flask, request, jsonify
from datetime import datetime
import logging
import hashlib
import re

app = Flask(__name__)

# Configure logging
logging.basicConfig(
    filename='application.log',
    level=logging.INFO,
    format='%(asctime)s - %(levelname)s - %(message)s'
)

# Simple user database (in production, use proper database)
users = {
    "admin": {
        "password": hashlib.sha256("password123".encode()).hexdigest(),
        "email": "admin@example.com"
    }
}

def sanitize_input(input_string):
    """Sanitize input to prevent log injection"""
    if not isinstance(input_string, str):
        return ""
    # Remove potentially dangerous characters
    sanitized = re.sub(r'[\r\n\t]', '', input_string)
    return sanitized[:255]  # Limit length

def log_login_attempt(username, password, email, ip_address, user_agent, success):
    """Log login attempt with sanitized data"""
    try:
        # Sanitize all inputs
        sanitized_username = sanitize_input(username)
        sanitized_email = sanitize_input(email)
        sanitized_ip = sanitize_input(ip_address)
        sanitized_user_agent = sanitize_input(user_agent)
        
        # Create log message
        log_message = f"LOGIN_ATTEMPT - Username: {sanitized_username}, Email: {sanitized_email}, IP: {sanitized_ip}, User-Agent: {sanitized_user_agent}, Success: {success}"
        
        # Log the attempt
        if success:
            logging.info(log_message)
        else:
            logging.warning(log_message)
            
    except Exception as e:
        # Fallback logging in case of logging errors
        try:
            logging.error(f"Failed to log login attempt: {str(e)}")
        except:
            pass  # If even this fails, silently continue

@app.route('/login', methods=['POST'])
def login():
    try:
        data = request.get_json()
        
        if not data:
            return jsonify({"error": "No data provided"}), 400
            
        username = data.get('username', '')
        password = data.get('password', '')
        email = data.get('email', '')
        
        # Get client information
        ip_address = request.remote_addr
        user_agent = request.headers.get('User-Agent', '')
        
        # Validate input
        if not username or not password:
            log_login_attempt(username, password, email, ip_address, user_agent, False)
            return jsonify({"error": "Username and password required"}), 400
            
        # Check if user exists and password matches
        if username in users:
            stored_password_hash = users[username]["password"]
            input_password_hash = hashlib.sha256(password.encode()).hexdigest()
            
            if stored_password_hash == input_password_hash:
                log_login_attempt(username, password, email, ip_address, user_agent, True)
                return jsonify({"message": "Login successful"}), 200
            else:
                log_login_attempt(username, password, email, ip_address, user_agent, False)
                return jsonify({"error": "Invalid credentials"}), 401
        else:
            log_login_attempt(username, password, email, ip_address, user_agent, False)
            return jsonify({"error": "Invalid credentials"}), 401
            
    except Exception as e:
        # Log unexpected errors
        try:
            ip_address = request.remote_addr
            user_agent = request.headers.get('User-Agent', '')
            logging.error(f"UNEXPECTED_ERROR - IP: {ip_address}, User-Agent: {user_agent}, Error: {str(e)}")
        except:
            pass
        return jsonify({"error": "Internal server error"}), 500

@app.route('/health', methods=['GET'])
def health_check():
    return jsonify({"status": "healthy"}), 200

if __name__ == '__main__':
    app.run(debug=False)